import React, { useEffect, useState } from "react";

export default function Internship() {
  const currentUser = JSON.parse(localStorage.getItem("currentUser"));
  const [internships, setInternships] = useState(
    JSON.parse(localStorage.getItem("internships")) || []
  );
  const [appliedIds, setAppliedIds] = useState(
    JSON.parse(localStorage.getItem("appliedInternships")) || []
  );
  const [formData, setFormData] = useState({
    company: "",
    role: "",
    stipend: "",
    duration: "",
    eligibility: "",
  });
  const [editIndex, setEditIndex] = useState(null);

  useEffect(() => {
    localStorage.setItem("internships", JSON.stringify(internships));
  }, [internships]);

  useEffect(() => {
    localStorage.setItem("appliedInternships", JSON.stringify(appliedIds));
  }, [appliedIds]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAdd = () => {
    if (
      !formData.company ||
      !formData.role ||
      !formData.stipend ||
      !formData.duration ||
      !formData.eligibility
    ) {
      alert("All fields are required.");
      return;
    }
    setInternships([
      ...internships,
      { ...formData, id: Date.now().toString() },
    ]);
    setFormData({
      company: "",
      role: "",
      stipend: "",
      duration: "",
      eligibility: "",
    });
  };

  const handleDelete = (id) => {
    const updated = internships.filter((item) => item.id !== id);
    setInternships(updated);
  };

  const handleEdit = (index) => {
    setEditIndex(index);
    setFormData(internships[index]);
  };

  const handleUpdate = () => {
    const updated = [...internships];
    updated[editIndex] = formData;
    setInternships(updated);
    setEditIndex(null);
    setFormData({
      company: "",
      role: "",
      stipend: "",
      duration: "",
      eligibility: "",
    });
  };

  const handleApply = (id) => {
    if (appliedIds.includes(id)) return;
    setAppliedIds([...appliedIds, id]);
    alert("Applied successfully!");
  };

  const handleCancel = (id) => {
    const updated = appliedIds.filter((appliedId) => appliedId !== id);
    setAppliedIds(updated);
    alert("Application cancelled.");
  };

  const canAdd = currentUser.role === "admin" || currentUser.role === "hr";
  const canEditDelete = currentUser.role === "admin";
  const isStudent = currentUser.role === "student";

  return (
    <div className="p-4">
      <h2 className="text-2xl font-bold mb-4">Internship Opportunities</h2>

      {canAdd && (
        <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-4">
          <input
            name="company"
            placeholder="Company"
            value={formData.company}
            onChange={handleChange}
            className="p-2 border rounded"
          />
          <input
            name="role"
            placeholder="Role"
            value={formData.role}
            onChange={handleChange}
            className="p-2 border rounded"
          />
          <input
            name="stipend"
            placeholder="Stipend"
            value={formData.stipend}
            onChange={handleChange}
            className="p-2 border rounded"
          />
          <input
            name="duration"
            placeholder="Duration"
            value={formData.duration}
            onChange={handleChange}
            className="p-2 border rounded"
          />
          <input
            name="eligibility"
            placeholder="Eligibility"
            value={formData.eligibility}
            onChange={handleChange}
            className="p-2 border rounded"
          />

          {editIndex !== null ? (
            <button
              onClick={handleUpdate}
              className="bg-yellow-500 text-white rounded px-4 py-2"
            >
              Update
            </button>
          ) : (
            <button
              onClick={handleAdd}
              className="bg-green-600 text-white rounded px-4 py-2"
            >
              Add Internship
            </button>
          )}
        </div>
      )}

      {internships.length === 0 ? (
        <p className="text-gray-500">No internship opportunities available.</p>
      ) : (
        <div className="grid gap-4">
          {internships.map((item, index) => (
            <div
              key={item.id}
              className="p-4 border rounded shadow-md bg-white"
            >
              <h3 className="text-lg font-semibold">{item.company}</h3>
              <p>Role: {item.role}</p>
              <p>Stipend: {item.stipend}</p>
              <p>Duration: {item.duration}</p>
              <p>Eligibility: {item.eligibility}</p>

              {canEditDelete && (
                <div className="mt-2 flex gap-2">
                  <button
                    onClick={() => handleEdit(index)}
                    className="bg-blue-500 text-white px-3 py-1 rounded"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(item.id)}
                    className="bg-red-500 text-white px-3 py-1 rounded"
                  >
                    Delete
                  </button>
                </div>
              )}

              {isStudent && (
                <div className="mt-3">
                  {appliedIds.includes(item.id) ? (
                    <>
                      <span className="inline-block px-4 py-2 bg-gray-400 text-white rounded mr-2">
                        Applied
                      </span>
                      <button
                        onClick={() => handleCancel(item.id)}
                        className="bg-red-500 text-white px-3 py-1 rounded"
                      >
                        Cancel
                      </button>
                    </>
                  ) : (
                    <button
                      onClick={() => handleApply(item.id)}
                      className="bg-blue-600 text-white px-4 py-2 rounded"
                    >
                      Apply
                    </button>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
